import { useState, useRef, useEffect } from "react";
export default function DealFinderAgent() {
  const [query, setQuery] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [thinkStage, setThinkStage] = useState(0);
  const timerRef = useRef(null);
  const bottomRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  useEffect(() => {
    if (loading) {
      timerRef.current = setInterval(() => setThinkStage(s => s + 1), 1200);
    } else {
      clearInterval(timerRef.current);
      setThinkStage(0);
    }
    return () => clearInterval(timerRef.current);
  }, [loading]);

  async function search() {
    const q = query.trim();
    if (!q || loading) return;
    setQuery("");
    setMessages(prev => [...prev, { role: "user", content: q }]);
    setLoading(true);

    const SYSTEM = `You are a smart e-commerce deal-finding agent for Indian shoppers. Search across Amazon India, Flipkart, Myntra, Meesho, Croma, Snapdeal and other relevant platforms.

Respond ONLY using this plain-text format — no JSON, no markdown, no code blocks:

SUMMARY: One or two sentences about what you found overall.

DEAL:
PLATFORM: Amazon
PRODUCT: Full product name with specs/variant
PRICE: ₹XX,XXX
WAS: ₹XX,XXX
DISCOUNT: XX%
OFFER: Any bank or coupon offer
RATING: 4.3
SPECS: Key specs in one line
LINK: https://www.amazon.in/...

DEAL:
PLATFORM: Flipkart
...repeat for each platform...

VERDICT: Your recommendation — which deal to pick and why.

Rules:
- Include 4–6 DEAL blocks across different platforms
- Prices in ₹ INR, realistic for India
- Skip platforms where the product doesn't make sense (e.g. clothes on Croma)
- Each field on its own line with the label and a colon
- No JSON, no backticks, no markdown formatting whatsoever`;

    try {
      const history = messages
        .filter(m => m.role === "user" || m.role === "assistant")
        .map(m => ({ role: m.role, content: typeof m.content === "string" ? m.content : "" }))
        .filter(m => m.content);
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: SYSTEM,
          tools: [{ type: "web_search_20250305", name: "web_search" }],
          messages: [...history, { role: "user", content: `Find me the best deals for: ${q}` }]
        })
      });

      const data = await res.json();

      // Collect all text content
      const text = (data.content || [])
        .filter(b => b.type === "text")
        .map(b => b.text)
        .join("\n");

      setMessages(prev => [...prev, { role: "assistant", content: text || "Sorry, I couldn't find deals right now. Try again!" }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: "assistant", content: "⚠️ Something went wrong while searching for deals. Please try again." }]);
    }

    setLoading(false);
    setTimeout(() => inputRef.current?.focus(), 100);
  }

  function handleKey(e) {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); search(); }
  }

  const isEmpty = messages.length === 0;

  return (
    <div style={{
      minHeight: "100vh",
      background: "#0a0a0a",
      color: "#e0e0e0",
      fontFamily: "'DM Sans', 'Segoe UI', system-ui, sans-serif",
      display: "flex", flexDirection: "column",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;700;900&family=DM+Mono:wght@400;500;700&display=swap');
        @keyframes slideUp { from { opacity: 0; transform: translateY(16px); } to { opacity: 1; transform: none; } }
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes bar { from { opacity: 0.3; } to { opacity: 1; } }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-thumb { background: #2a2a2a; border-radius: 4px; }
        * { box-sizing: border-box; }
        textarea { outline: none; }
        button { cursor: pointer; }
      `}</style>

      {/* Header */}
      <div style={{
        padding: "20px 24px 16px",
        borderBottom: "1px solid #1a1a1a",
        background: "#0a0a0a",
        display: "flex", alignItems: "center", gap: 14,
        position: "sticky", top: 0, zIndex: 10
      }}>
        <div style={{
          width: 44, height: 44, borderRadius: 14,
          background: "linear-gradient(135deg, #f59e0b, #ef4444)",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 22, boxShadow: "0 0 24px #f59e0b55", flexShrink: 0
        }}>🛍️</div>
        <div>
          <div style={{ fontWeight: 900, fontSize: 18, letterSpacing: -0.5, color: "#fff" }}>
            Deal<span style={{ color: "#f59e0b" }}>Hunter</span> AI
          </div>
          <div style={{ fontSize: 11, color: "#555", fontFamily: "'DM Mono', monospace", letterSpacing: 1 }}>
            COMPARING {PLATFORMS.length} PLATFORMS · INDIA
          </div>
        </div>
        <div style={{ marginLeft: "auto", display: "flex", gap: 6, flexWrap: "wrap", justifyContent: "flex-end" }}>
          {PLATFORMS.map(p => (
            <span key={p.name} title={p.name} style={{
              fontSize: 16, cursor: "default", opacity: 0.8,
              filter: "grayscale(0.2)"
            }}>{p.icon}</span>
          ))}
        </div>
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflowY: "auto", padding: "24px 16px", maxWidth: 760, margin: "0 auto", width: "100%" }}>
        {isEmpty ? (
          <div style={{ animation: "fadeIn 0.5s ease", textAlign: "center", paddingTop: 40 }}>
            <div style={{ fontSize: 56, marginBottom: 16 }}>🔍</div>
            <div style={{ fontSize: 22, fontWeight: 900, color: "#fff", marginBottom: 8 }}>
              Find the Best Deals Instantly
            </div>
            <div style={{ color: "#555", fontSize: 14, marginBottom: 40 }}>
              I compare prices across Amazon, Flipkart, Myntra & more — saving you time & money.
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, maxWidth: 560, margin: "0 auto" }}>
              {SUGGESTIONS.map((s, i) => (
                <button key={i} onClick={() => { setQuery(s); setTimeout(() => inputRef.current?.focus(), 50); }}
                  style={{
                    background: "#141414", border: "1px solid #222",
                    borderRadius: 12, padding: "12px 14px",
                    color: "#bbb", fontSize: 13, textAlign: "left",
                    transition: "all 0.2s", lineHeight: 1.4,
                    animation: `slideUp 0.4s ${i * 0.06}s both ease-out`
                  }}
                  onMouseEnter={e => { e.currentTarget.style.borderColor = "#f59e0b"; e.currentTarget.style.color = "#fff"; }}
                  onMouseLeave={e => { e.currentTarget.style.borderColor = "#222"; e.currentTarget.style.color = "#bbb"; }}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 24 }}>
            {messages.map((msg, i) => (
              <div key={i} style={{ animation: "slideUp 0.3s ease" }}>
                {msg.role === "user" ? (
                  <div style={{ display: "flex", justifyContent: "flex-end" }}>
                    <div style={{
                      background: "linear-gradient(135deg, #f59e0b, #ef4444)",
                      color: "#000", fontWeight: 700, fontSize: 14,
                      borderRadius: "18px 18px 4px 18px",
                      padding: "12px 18px", maxWidth: "70%",
                      boxShadow: "0 4px 20px #f59e0b44"
                    }}>{msg.content}</div>
                  </div>
                ) : (
                  <div style={{
                    background: "#111", border: "1px solid #1e1e1e",
                    borderRadius: 18, padding: "18px 20px"
                  }}>
                    <div style={{
                      display: "flex", alignItems: "center", gap: 8, marginBottom: 14,
                      paddingBottom: 10, borderBottom: "1px solid #1e1e1e"
                    }}>
                      <span style={{ fontSize: 16 }}>🤖</span>
                      <span style={{ color: "#f59e0b", fontSize: 12, fontWeight: 700, fontFamily: "'DM Mono', monospace", letterSpacing: 1 }}>
                        DEALHUNTER AGENT
                      </span>
                    </div>
                    <ResultBlock content={msg.content} />
                  </div>
                )}
              </div>
            ))}
            {loading && (
              <div style={{ animation: "slideUp 0.3s ease" }}>
                <div style={{ background: "#111", border: "1px solid #1e1e1e", borderRadius: 18, padding: "18px 20px" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 14, paddingBottom: 10, borderBottom: "1px solid #1e1e1e" }}>
                    <span style={{ fontSize: 16 }}>🤖</span>
                    <span style={{ color: "#f59e0b", fontSize: 12, fontWeight: 700, fontFamily: "'DM Mono', monospace", letterSpacing: 1 }}>
                      DEALHUNTER AGENT
                    </span>
                  </div>
                  <ThinkingState stage={thinkStage} />
                </div>
              </div>
            )}
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div style={{
        padding: "16px", borderTop: "1px solid #1a1a1a",
