              onKeyDown={handleKey}
              placeholder="Search for any product… e.g. 'best deal on AirPods Pro'"
              disabled={loading}
              rows={1}
              style={{
                width: "100%", background: "#141414",
                border: "1.5px solid #2a2a2a", borderRadius: 14,
                padding: "13px 16px", paddingRight: 48,
                color: "#e0e0e0", fontSize: 14,
                fontFamily: "'DM Sans', system-ui, sans-serif",
