function SavingsSummary({ deals }) {
  if (!deals || deals.length < 2) return null;
  const prices = deals.map(d => {
    const num = parseFloat(d.price?.replace(/[^0-9.]/g, ""));
    return isNaN(num) ? null : num;
  }).filter(Boolean);
  if (prices.length < 2) return null;
  const min = Math.min(...prices);
  const max = Math.max(...prices);
  const savings = max - min;
  if (savings <= 0) return null;
  return (
    <div style={{
      background: "#22c55e15", border: "1px solid #22c55e33",
      borderRadius: 12, padding: "12px 16px", marginBottom: 16,
      display: "flex", alignItems: "center", gap: 12
    }}>
      <span style={{ fontSize: 24 }}>💰</span>
      <div>
        <div style={{ color: "#22c55e", fontWeight: 800, fontSize: 15, fontFamily: "'DM Mono', monospace" }}>
          Save up to ₹{savings.toLocaleString("en-IN")}
        </div>
        <div style={{ color: "#888", fontSize: 12 }}>by choosing the best deal over the most expensive option</div>
      </div>
    </div>
  );
}

