      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: SYSTEM,
          tools: [{ type: "web_search_20250305", name: "web_search" }],
          messages: [...history, { role: "user", content: `Find me the best deals for: ${q}` }]
        })
      });

      const data = await res.json();

      // Collect all text content
      const text = (data.content || [])
        .filter(b => b.type === "text")
        .map(b => b.text)
        .join("\n");

      setMessages(prev => [...prev, { role: "assistant", content: text || "Sorry, I couldn't find deals right now. Try again!" }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: "assistant", content: "⚠️ Something went wrong while searching for deals. Please try again." }]);
    }

    setLoading(false);
    setTimeout(() => inputRef.current?.focus(), 100);
