function parseDeals(text) {
  const deals = [];
  // Split on DEAL: markers
  const blocks = text.split(/\n(?=DEAL:)/);
  for (const block of blocks) {
    if (!block.trim().startsWith("DEAL:")) continue;
    const get = (key) => {
      const m = block.match(new RegExp(`${key}:\\s*(.+)`));
      return m ? m[1].trim() : "";
    };
    deals.push({
      platform: get("PLATFORM"),
      productName: get("PRODUCT"),
      price: get("PRICE"),
      originalPrice: get("WAS"),
      discount: get("DISCOUNT"),
      offer: get("OFFER"),
      rating: parseFloat(get("RATING")) || null,
      highlights: get("SPECS"),
      link: get("LINK"),
    });
  }
  return deals;
}

