function ResultBlock({ content }) {
  // Extract SUMMARY, VERDICT, and DEAL blocks
  const summaryMatch = content.match(/SUMMARY:\s*(.+)/);
  const verdictMatch = content.match(/VERDICT:\s*([\s\S]+?)(?=\nDEAL:|\nSUMMARY:|$)/);
  const summary = summaryMatch ? summaryMatch[1].trim() : "";
  const verdict = verdictMatch ? verdictMatch[1].trim() : "";

  const deals = parseDeals(content);

  if (deals.length > 0) {
    const sorted = [...deals].sort((a, b) => {
      const pa = parseFloat(a.price?.replace(/[^0-9.]/g, "")) || Infinity;
      const pb = parseFloat(b.price?.replace(/[^0-9.]/g, "")) || Infinity;
      return pa - pb;
    });

    return (
      <div>
        {summary && (
          <div style={{ color: "#aaa", fontSize: 13, marginBottom: 16, lineHeight: 1.6 }}>{summary}</div>
        )}
        <SavingsSummary deals={sorted} />
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {sorted.map((deal, i) => <DealCard key={i} deal={deal} rank={i} />)}
        </div>
        {verdict && (
          <div style={{
            marginTop: 16, padding: "12px 16px",
            background: "#f59e0b18", border: "1px solid #f59e0b33",
            borderRadius: 12, color: "#f59e0b", fontSize: 13, lineHeight: 1.6
          }}>
            <strong>🤖 Agent Verdict:</strong> {verdict}
          </div>
        )}
      </div>
    );
  }

  // Fallback: plain readable text
  return (
    <div style={{ color: "#d0d0d0", fontSize: 14, lineHeight: 1.7, whiteSpace: "pre-wrap" }}>
      {content}
    </div>
  );
}

