function DealFinderAgent() {
  const [query, setQuery] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [thinkStage, setThinkStage] = useState(0);
  const timerRef = useRef(null);
  const bottomRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  useEffect(() => {
    if (loading) {
      timerRef.current = setInterval(() => setThinkStage(s => s + 1), 1200);
    } else {
      clearInterval(timerRef.current);
      setThinkStage(0);
    }
    return () => clearInterval(timerRef.current);
  }, [loading]);

  async function search() {
    const q = query.trim();
    if (!q || loading) return;
    setQuery("");
    setMessages(prev => [...prev, { role: "user", content: q }]);
    setLoading(true);

    // Step 1: Fetch real-time search results from SerpApi
    let searchContext = "";
    try {
      const platforms = ["Amazon India", "Flipkart", "Myntra", "Meesho", "Croma", "Snapdeal"];
      const PLATFORM_DOMAINS = {
        "Amazon India": "amazon.in",
        "Flipkart": "flipkart.com",
        "Myntra": "myntra.com",
        "Meesho": "meesho.com",
        "Croma": "croma.com",
        "Snapdeal": "snapdeal.com",
      };
      const searchResults = await Promise.all(
        platforms.map(platform => {
          const domain = PLATFORM_DOMAINS[platform];
          return fetch(`/api/serpapi/search.json?q=${encodeURIComponent(q + " site:" + domain)}&api_key=${import.meta.env.VITE_SERPAPI_KEY}&num=5&gl=in&hl=en`)
            .then(r => r.json())
            .then(data => ({
              platform,
              results: (data.organic_results || [])
                .filter(r => r.link?.includes(domain))
                .slice(0, 2)
                .map(r => ({ title: r.title, snippet: r.snippet, link: r.link }))
            }))
            .catch(() => ({ platform, results: [] }));
        })
      );

      searchContext = searchResults
        .filter(s => s.results.length > 0)
        .map(s => `${s.platform}:\n${s.results.map(r => `- ${r.title}\n  ${r.snippet}\n  URL: ${r.link}`).join("\n")}`)
        .join("\n\n");
    } catch (e) {
      searchContext = "";
    }

    const SYSTEM = `You are a smart e-commerce deal-finding agent for Indian shoppers.
${
  searchContext
    ? `Use ONLY the following REAL live search results to extract current prices. Do not make up prices.\n\nLIVE SEARCH DATA:\n${searchContext}`
    : "Use your knowledge to provide realistic Indian market prices."
}

Respond ONLY using this plain-text format — no JSON, no markdown, no code blocks:

SUMMARY: One or two sentences about what you found overall.

DEAL:
PLATFORM: Amazon
PRODUCT: Full product name with specs/variant
PRICE: ₹XX,XXX
WAS: ₹XX,XXX
DISCOUNT: XX%
OFFER: Any bank or coupon offer
RATING: 4.3
SPECS: Key specs in one line
LINK: https://www.amazon.in/...

DEAL:
PLATFORM: Flipkart
...repeat for each platform...

VERDICT: Your recommendation — which deal to pick and why.

Rules:
- Include 4–6 DEAL blocks across different platforms
- Extract REAL prices from the search data provided above
- Prices in ₹ INR
- Use the actual URLs from the search data for LINK fields
- LINK must only be from these domains: amazon.in, flipkart.com, myntra.com, meesho.com, croma.com, snapdeal.com
- NEVER use links from instagram.com, youtube.com, facebook.com, twitter.com, blogs, or any non-ecommerce site
- If no valid product link is available for a platform, omit the LINK field entirely
- Each field on its own line with the label and a colon
- No JSON, no backticks, no markdown formatting whatsoever`;

    try {
      const history = messages
        .filter(m => m.role === "user" || m.role === "assistant")
        .map(m => ({ role: m.role, content: typeof m.content === "string" ? m.content : "" }))
        .filter(m => m.content);
      const res = await fetch("/api/groq/openai/v1/chat/completions", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${import.meta.env.VITE_GROQ_API_KEY}`,
        },
        body: JSON.stringify({
          model: "llama-3.3-70b-versatile",
          max_tokens: 1500,
          messages: [
            { role: "system", content: SYSTEM },
            ...history,
            { role: "user", content: `Find me the best deals for: ${q}` }
          ]
        })
      });

      const data = await res.json();
      const text = data.choices?.[0]?.message?.content || "";

      setMessages(prev => [...prev, { role: "assistant", content: text || "Sorry, I couldn't find deals right now. Try again!" }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: "assistant", content: `⚠️ Error: ${err.message}` }]);
    }

    setLoading(false);
    setTimeout(() => inputRef.current?.focus(), 100);
  }

  function handleKey(e) {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); search(); }
  }

  const isEmpty = messages.length === 0;

